function parseBody(json) {
  if (!json || typeof json !== 'object') return {};
  let b = json.body;
  if (typeof b === 'string') {
    try { b = JSON.parse(b); } catch (e) { b = null; }
  }
  if (b && typeof b === 'object' && !Array.isArray(b)) return b;
  if (json.photo_urls || json.text || json.event) return json;
  return {};
}

function extractUrls(b) {
  const arr = Array.isArray(b.photo_urls)
    ? b.photo_urls
    : (Array.isArray(b.photoUrls) ? b.photoUrls : []);
  return arr
    .map((u) => String(u || '').trim())
    .filter((u) => u.startsWith('http'))
    .slice(0, 10);
}

function pickPayload() {
  const input = $input.first().json;
  let body = parseBody(input);
  if (extractUrls(body).length || body.text) return { input, body };
  try {
    const wh = $('Webhook Publish').first().json;
    body = parseBody(wh);
  } catch (e) {}
  return { input, body };
}

const { input, body } = pickPayload();
const photoUrls = extractUrls(body);
const textFull = String(body.text || '').trim();
const caption = textFull.length <= 980 ? textFull : textFull.slice(0, 979) + '…';

return [{
  json: {
    chatId: String(input.telegramChatId || '').trim(),
    botToken: String(input.telegramBotToken || '').trim(),
    textFull,
    caption,
    photoUrls,
    photoCount: photoUrls.length,
  },
}];

function normalizeUrl(u) {
  const s = String(u || '').trim();
  return s.startsWith('http') ? s : '';
}

function addUrls(out, seen, list) {
  if (!Array.isArray(list)) return;
  for (const u of list) {
    const s = normalizeUrl(u);
    if (s && !seen.has(s)) {
      seen.add(s);
      out.push(s);
    }
  }
}

function urlsFromJson(json) {
  if (!json || typeof json !== 'object') return [];
  const out = [];
  const seen = new Set();
  addUrls(out, seen, json.photoUrls);
  addUrls(out, seen, json.photo_urls);
  const body = json.body;
  if (body && typeof body === 'object') {
    addUrls(out, seen, body.photo_urls);
    addUrls(out, seen, body.photoUrls);
  }
  if (json.photoUrls && typeof json.photoUrls === 'object' && !Array.isArray(json.photoUrls)) {
    addUrls(out, seen, Object.values(json.photoUrls));
  }
  return out.slice(0, 10);
}

function pickRow() {
  const inputJson = $input.first()?.json;
  if (inputJson) return inputJson;
  for (const name of ['Данные для поста', 'Данные для поста1']) {
    try {
      const j = $(name).first()?.json;
      if (j) return j;
    } catch (e) {}
  }
  try {
    const wh = $('Webhook Publish').first()?.json;
    if (wh) return wh.body && typeof wh.body === 'object' ? { ...wh.body, body: wh.body } : wh;
  } catch (e) {}
  return {};
}

function pickSettings() {
  try {
    return $('Настройки Telegram').first()?.json || {};
  } catch (e) {
    return {};
  }
}

const row = pickRow();
const settings = pickSettings();
const urls = urlsFromJson(row);
if (urls.length < 2) {
  const debug = [
    'photoCount=' + (row.photoCount ?? '?'),
    'photoUrls=' + JSON.stringify(row.photoUrls ?? null).slice(0, 180),
    'keys=' + Object.keys(row).join(','),
  ].join('; ');
  throw new Error('Для альбома нужно минимум 2 URL, получено ' + urls.length + '. ' + debug);
}

const chatId = String(row.chatId || settings.telegramChatId || '').trim();
if (!chatId) {
  throw new Error('Не задан chat ID: укажите telegramChatId в узле «Настройки Telegram».');
}

const botToken = String(row.botToken || settings.telegramBotToken || '').trim();
if (!botToken || botToken.includes('REPLACE')) {
  throw new Error('Не задан bot token: укажите telegramBotToken в узле «Настройки Telegram» (тот же, что в credential).');
}

const capRaw = String(row.textFull || row.text || '').trim();
const cap = capRaw.length <= 1024 ? capRaw : String(row.caption || '').trim().slice(0, 1024);

const media = urls.slice(0, 10).map((u, i) => {
  const item = { type: 'photo', media: u };
  if (i === 0 && cap) item.caption = cap;
  return item;
});

return [{ json: { chat_id: chatId, media, botToken } }];
